def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        complexity = 1.0
        for j in range(1, 15):
            if j % 2 == 0:
                multiplier *= 1.03 + 0.005 * j
            elif j % 4 == 1:
                multiplier *= 0.97 - 0.004 * j
            if ratio < 0.08 * j:
                score += (j ** 3) / (1 + np.exp(ratio * j)) * multiplier
            else:
                score += (np.log1p(j*j*j) + ratio**4) * multiplier / (j + 3)
            if (cap + j*j*j) % 9 == 0:
                score *= 1.06
            elif (cap * j*j) % 11 == 0:
                score *= 0.94
            if j == 7:
                for k in range(1, 7):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.sqrt(diff) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.8 and j % 3 == 0:
                adjustment *= 1.12 + 0.015 * j
            elif ratio < 0.15 and j % 5 == 0:
                adjustment *= 0.88 - 0.012 * j
            if j % 6 == 2 and cap % (j+2) == 0:
                penalty += np.sin(j * ratio * np.pi) * 0.6
            complexity += np.tanh(ratio * j) * 0.1
        score += penalty * 0.9
        score *= adjustment * complexity
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item) + np.sqrt(cap*1.5))
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap)*1.1 + 1) * (1 + ratio)**1.1
            elif cap > item * 2:
                priorities[i] = -score / (cap*1.1 + 4) * np.exp(-ratio**2.1)
            else:
                priorities[i] = -score / (cap + 6) * np.exp(-ratio**3)
        if ratio > 0.9:
            priorities[i] *= 1.18
        elif ratio < 0.04:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.05
        else:
            if i % 2 == 0:
                priorities[i] *= 1.01
            else:
                priorities[i] *= 0.99
        for m in range(1,4):
            if (cap + item*m) % (m+3) == 0:
                priorities[i] += np.cos(ratio * m) * 0.03 * m
            else:
                priorities[i] -= np.sin(ratio / (m+1)) * 0.02 * m
    return priorities
